-- ── Link recipes to ingredient groups ────────────────────────
-- We use recipe name matching for maintainability
do $$
declare
  r_id bigint;
  g_id bigint;

  procedure link(recipe_name text, group_name text, is_required boolean default true) as $$
  begin
    select id into r_id from recipes where name = recipe_name limit 1;
    select id into g_id from ingredient_groups where name = group_name limit 1;
    if r_id is not null and g_id is not null then
      insert into recipe_ingredients (recipe_id, ingredient_group_id, required)
      values (r_id, g_id, is_required)
      on conflict do nothing;
    end if;
  end;
begin
  -- Паста Карбонара
  call link('Паста Карбонара', 'паста'); call link('Паста Карбонара', 'бекон'); call link('Паста Карбонара', 'яйца'); call link('Паста Карбонара', 'сыр твёрдый');
  -- Мак-н-Чиз
  call link('Мак-н-Чиз', 'паста'); call link('Мак-н-Чиз', 'сыр твёрдый'); call link('Мак-н-Чиз', 'молоко'); call link('Мак-н-Чиз', 'сливочное масло'); call link('Мак-н-Чиз', 'мука');
  -- Болоньезе
  call link('Болоньезе', 'паста'); call link('Болоньезе', 'фарш мясной'); call link('Болоньезе', 'лук'); call link('Болоньезе', 'томатная паста'); call link('Болоньезе', 'сыр твёрдый', false);
  -- Паста с курицей и сливками
  call link('Паста с курицей и сливками', 'паста'); call link('Паста с курицей и сливками', 'куриное филе'); call link('Паста с курицей и сливками', 'сливки'); call link('Паста с курицей и сливками', 'сыр твёрдый', false);
  -- Лазанья
  call link('Лазанья', 'паста'); call link('Лазанья', 'фарш мясной'); call link('Лазанья', 'молоко'); call link('Лазанья', 'сыр твёрдый'); call link('Лазанья', 'сливочное масло');
  -- Плов
  call link('Плов', 'рис'); call link('Плов', 'говядина'); call link('Плов', 'лук'); call link('Плов', 'морковь'); call link('Плов', 'специи');
  -- Котлеты классические
  call link('Котлеты классические', 'фарш мясной'); call link('Котлеты классические', 'лук'); call link('Котлеты классические', 'яйца'); call link('Котлеты классические', 'хлеб/тост', false);
  -- Курица в сметане
  call link('Курица в сметане', 'куриное филе'); call link('Курица в сметане', 'сметана'); call link('Курица в сметане', 'лук');
  -- Бефстроганов
  call link('Бефстроганов', 'говядина'); call link('Бефстроганов', 'лук'); call link('Бефстроганов', 'сметана');
  -- Рыба в духовке с лимоном
  call link('Рыба в духовке с лимоном', 'рыба любая'); call link('Рыба в духовке с лимоном', 'лимон/лайм'); call link('Рыба в духовке с лимоном', 'зелень'); call link('Рыба в духовке с лимоном', 'специи');
  -- Уха классическая
  call link('Уха классическая', 'рыба любая'); call link('Уха классическая', 'картошка'); call link('Уха классическая', 'лук'); call link('Уха классическая', 'морковь'); call link('Уха классическая', 'зелень');
  -- Борщ классический
  call link('Борщ классический', 'говядина'); call link('Борщ классический', 'капуста'); call link('Борщ классический', 'картошка'); call link('Борщ классический', 'лук'); call link('Борщ классический', 'морковь'); call link('Борщ классический', 'томатная паста'); call link('Борщ классический', 'сметана', false);
  -- Греческий салат
  call link('Греческий салат', 'помидоры'); call link('Греческий салат', 'огурцы'); call link('Греческий салат', 'сыр мягкий'); call link('Греческий салат', 'зелень');
  -- Цезарь с курицей
  call link('Цезарь с курицей', 'куриное филе'); call link('Цезарь с курицей', 'сыр твёрдый'); call link('Цезарь с курицей', 'хлеб/тост'); call link('Цезарь с курицей', 'майонез');
  -- Оливье
  call link('Оливье', 'яйца'); call link('Оливье', 'картошка'); call link('Оливье', 'морковь'); call link('Оливье', 'колбаса'); call link('Оливье', 'майонез');
  -- Блины классические
